import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, Cpu } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please enter details.');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back to Finify!');
      navigate('/dashboard'); 
    } catch (err) { 
      toast.error('Could not log in.'); 
    } 
    finally { setLoading(false); }
  };

  return (
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center p-6 reveal-node">
      {/* Ambient Glow */}
      <div className="absolute -top-32 -left-32 w-64 h-64" style={{ background: 'var(--accent-glow)', borderRadius: '50%', filter: 'blur(80px)', opacity: 0.5 }} />
      
      {/* Login Card */}
      <div className="w-full max-w-md vault-card" style={{ padding: '2.5rem' }}>
        {/* Header */}
        <div className="text-center mb-10">
          <div className="flex justify-center mb-4" style={{ color: 'var(--accent-primary)' }}>
            <Cpu size={42} className="animate-pulse" />
          </div>
          <h1 className="text-3xl font-light tracking-tight mb-2" style={{ color: 'var(--text-primary)' }}>
            Welcome Back
          </h1>
          <p className="text-xs uppercase tracking-[0.25em]" style={{ color: 'var(--text-muted)' }}>
            Sign in to access your node
          </p>
        </div>
        
        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Email Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest ml-1" style={{ color: 'var(--accent-primary)' }}>
              <span>Email Address</span>
            </label>
            <input 
                type="email" 
                placeholder="operator@finify.ai" 
                value={email} 
                onChange={(e) => setEmail(e.target.value)} 
                className="cyber-input"
                style={{ 
                  backgroundColor: 'var(--input-bg)',
                  borderColor: 'var(--input-border)',
                  color: 'var(--text-primary)'
                }}
                required
            />
          </div>
          
          {/* Password Field */}
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest ml-1" style={{ color: 'var(--accent-primary)' }}>
              <span>Master Key</span>
            </label>
            <div className="relative">
              <input 
                  type={showPass ? "text" : "password"} 
                  placeholder="••••••••" 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)} 
                  className="cyber-input pr-12"
                  style={{ 
                    backgroundColor: 'var(--input-bg)',
                    borderColor: 'var(--input-border)',
                    color: 'var(--text-primary)'
                  }}
                  required
              />
              <button 
                type="button" 
                onClick={() => setShowPass(!showPass)} 
                className="absolute right-4 top-1/2 -translate-y-1/2 cursor-pointer"
                style={{ color: 'var(--text-muted)' }}
              >
                {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>
          
          {/* Submit Button */}
          <button 
            type="submit" 
            className="cyber-btn mt-6 w-full"
            style={{ 
              backgroundImage: 'linear-gradient(135deg, var(--accent-secondary), var(--accent-primary))' 
            }}
            disabled={loading}
          >
            {loading ? 'SYNCHRONIZING...' : 'Sign In'}
          </button>
        </form>
        
        {/* Footer */}
        <div className="mt-10 pt-8 border-t text-center" style={{ borderColor: 'var(--surface-border)' }}>
          <p className="text-xs uppercase tracking-[0.25em]" style={{ color: 'var(--text-muted)' }}>
            Don't have an account?{' '}
            <Link to="/register" style={{ color: 'var(--accent-primary)' }} className="hover:underline">
              Sign Up
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};
export default LoginPage;
